import{_ as o,C as t,o as e,c as l,a2 as s,b as n,w as r,a as d,E as p,a3 as c}from"./chunks/framework.CkslIjGF.js";const q=JSON.parse('{"title":"Visão Geral","description":"","frontmatter":{},"headers":[],"relativePath":"getting-started/overview.md","filePath":"getting-started/overview.md"}'),u={name:"getting-started/overview.md"};function h(m,a,k,g,E,v){const i=t("Mermaid");return e(),l("div",null,[a[1]||(a[1]=s(`<h1 id="visao-geral" tabindex="-1">Visão Geral <a class="header-anchor" href="#visao-geral" aria-label="Permalink to &quot;Visão Geral&quot;">​</a></h1><h2 id="o-que-e-o-torukr" tabindex="-1">O que é o Torukr? <a class="header-anchor" href="#o-que-e-o-torukr" aria-label="Permalink to &quot;O que é o Torukr?&quot;">​</a></h2><p>O <strong>Torukr</strong> é uma plataforma declarativa para orquestrar aplicações, servidores VPS, redes privadas e recursos de infraestrutura de forma simples, segura e previsível.</p><p>Ele foi criado para quem precisa operar aplicações distribuídas em múltiplos servidores, mas não quer assumir toda a complexidade operacional de um cluster Kubernetes completo.</p><p>Com o Torukr, você descreve o estado desejado da sua infraestrutura em manifests YAML — nodes, apps, networks e resources — e a plataforma se encarrega de aplicar, reconciliar e manter esse estado nos servidores.</p><p>Em vez de acessar cada VPS manualmente via SSH, configurar Docker, redes, certificados e comunicação entre serviços de forma separada, o Torukr centraliza o controle e automatiza a operação.</p><p>O Torukr não tenta substituir Kubernetes em cenários de grande escala. Ele oferece uma alternativa mais simples para quem quer organização, manifests declarativos e controle multi-node sem carregar toda a complexidade de um cluster Kubernetes completo.</p><h2 id="para-que-serve-o-torukr" tabindex="-1">Para que serve o Torukr? <a class="header-anchor" href="#para-que-serve-o-torukr" aria-label="Permalink to &quot;Para que serve o Torukr?&quot;">​</a></h2><p>O Torukr transforma um conjunto de servidores VPS em uma plataforma organizada para deploy e operação de aplicações.</p><p>Com ele, você pode:</p><ul><li>Registrar servidores como <strong>nodes</strong></li><li>Criar <strong>networks</strong> privadas entre nodes</li><li>Fazer deploy de <strong>apps</strong> containerizadas</li><li>Declarar serviços auxiliares como <strong>resources</strong></li><li>Usar manifests YAML para versionar infraestrutura no Git</li><li>Aplicar mudanças com <code>torukrctl apply</code></li><li>Reduzir a necessidade de SSH manual em cada servidor</li><li>Operar ambientes multi-node com uma camada declarativa mais simples que Kubernetes</li></ul><h2 id="por-que-nao-apenas-docker-puro" tabindex="-1">Por que não apenas Docker puro? <a class="header-anchor" href="#por-que-nao-apenas-docker-puro" aria-label="Permalink to &quot;Por que não apenas Docker puro?&quot;">​</a></h2><p>Docker é excelente para rodar containers, mas não resolve sozinho a operação de múltiplos servidores.</p><p>Quando a aplicação começa a crescer, surgem perguntas como:</p><ul><li>Em qual servidor cada aplicação deve rodar?</li><li>Como conectar serviços em VPS diferentes?</li><li>Como padronizar deploys?</li><li>Como evitar configuração manual via SSH?</li><li>Como versionar infraestrutura?</li><li>Como repetir o mesmo ambiente em outro servidor?</li><li>Como configurar comunicação segura entre nodes?</li><li>Como saber o estado desejado versus o estado real?</li></ul><p>O Torukr usa Docker nos nodes, mas adiciona uma camada de orquestração, controle, rede e configuração declarativa.</p><h2 id="por-que-nao-kubernetes" tabindex="-1">Por que não Kubernetes? <a class="header-anchor" href="#por-que-nao-kubernetes" aria-label="Permalink to &quot;Por que não Kubernetes?&quot;">​</a></h2><p>Kubernetes é poderoso, mas muitas vezes é maior do que o problema.</p><p>Para homelabs, SaaS pequenos, aplicações internas, ambientes VPS e times pequenos, Kubernetes pode trazer:</p><ul><li>Curva de aprendizado alta</li><li>Muitos componentes obrigatórios</li><li>Operação complexa</li><li>Custo maior de infraestrutura</li><li>Excesso de abstrações para cenários simples</li></ul><p>O Torukr busca uma abordagem mais direta:</p><ul><li>Menos componentes</li><li>Mais fácil de instalar</li><li>Mais próximo do ambiente VPS tradicional</li><li>Manifests declarativos</li><li>CLI familiar</li><li>Rede privada entre nodes</li><li>Controle centralizado</li><li>Operação mais simples para projetos menores</li></ul><h2 id="ideia-central" tabindex="-1">Ideia central <a class="header-anchor" href="#ideia-central" aria-label="Permalink to &quot;Ideia central&quot;">​</a></h2><blockquote><p>Descreva o que você quer rodar. O Torukr decide como aplicar isso nos seus servidores.</p></blockquote><p>Exemplo:</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">apiVersion</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">platform.torukr.io/v1alpha1</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">kind</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">App</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">metadata</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  name</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">api</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">spec</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  image</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">ghcr.io/example/api:1.0.0</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  ports</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    - </span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">containerPort</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">8080</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  networks</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    - </span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">name</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">private</span></span></code></pre></div><p>Depois:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">torukrctl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apply</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -f</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> app.yaml</span></span></code></pre></div><p>O Torukr lê o manifesto, registra o estado desejado e reconcilia a aplicação nos nodes disponíveis.</p><h2 id="arquitetura-em-alto-nivel" tabindex="-1">Arquitetura em Alto Nível <a class="header-anchor" href="#arquitetura-em-alto-nivel" aria-label="Permalink to &quot;Arquitetura em Alto Nível&quot;">​</a></h2>`,30)),(e(),n(c,null,{default:r(()=>[p(i,{id:"mermaid-229",class:"mermaid",graph:"flowchart%20TD%0A%20%20%20%20CLI%5Btorukrctl%5D%20--%3E%7CHTTP%2FJWT%7C%20API%5BAPI%20Server%5D%0A%20%20%20%20Dashboard%5BDashboard%20Web%5D%20--%3E%7CHTTP%2FJWT%7C%20API%0A%20%20%20%20API%20--%3E%7CPostgreSQL%7C%20DB%5B(Banco%20de%20Dados)%5D%0A%20%20%20%20API%20--%3E%20Controller%5BController%5D%0A%20%20%20%20Controller%20--%3E%7CmTLS%7C%20NR1%5BNodeRuntime%20-%20Node%201%5D%0A%20%20%20%20Controller%20--%3E%7CmTLS%7C%20NR2%5BNodeRuntime%20-%20Node%202%5D%0A%20%20%20%20NR1%20--%3E%7CDocker%20SDK%7C%20Docker1%5BDocker%20-%20VPS%201%5D%0A%20%20%20%20NR2%20--%3E%7CDocker%20SDK%7C%20Docker2%5BDocker%20-%20VPS%202%5D%0A%20%20%20%20NR1%20%3C--%3E%7CWireGuard%20%2B%20VXLAN%7C%20NR2%0A"})]),fallback:r(()=>[...a[0]||(a[0]=[d(" Loading... ",-1)])]),_:1})),a[2]||(a[2]=s('<h2 id="componentes" tabindex="-1">Componentes <a class="header-anchor" href="#componentes" aria-label="Permalink to &quot;Componentes&quot;">​</a></h2><h3 id="api-server" tabindex="-1">API Server <a class="header-anchor" href="#api-server" aria-label="Permalink to &quot;API Server&quot;">​</a></h3><p>Exposição HTTP/HTTPS com autenticação JWT. Recebe comandos do <code>torukrctl</code> e do dashboard web. Armazena o estado em PostgreSQL.</p><h3 id="controller" tabindex="-1">Controller <a class="header-anchor" href="#controller" aria-label="Permalink to &quot;Controller&quot;">​</a></h3><p>Processo que monitora constantemente o estado dos recursos e reconcilia diferenças. Quando você cria um App, o Controller determina qual node deve rodá-lo e instrui o NodeRuntime correspondente.</p><h3 id="noderuntime" tabindex="-1">NodeRuntime <a class="header-anchor" href="#noderuntime" aria-label="Permalink to &quot;NodeRuntime&quot;">​</a></h3><p>Agente que roda em cada VPS. Recebe instruções do Controller via mTLS e as executa usando o Docker SDK.</p><h3 id="torukrctl" tabindex="-1">torukrctl <a class="header-anchor" href="#torukrctl" aria-label="Permalink to &quot;torukrctl&quot;">​</a></h3><p>CLI com comandos familiares (<code>get</code>, <code>describe</code>, <code>apply</code>, <code>delete</code>) para interagir com a API do Torukr.</p><h2 id="proximos-passos" tabindex="-1">Próximos Passos <a class="header-anchor" href="#proximos-passos" aria-label="Permalink to &quot;Próximos Passos&quot;">​</a></h2><ul><li><a href="/getting-started/installation.html">Instalar o Torukr</a></li><li><a href="/getting-started/quickstart.html">Início Rápido</a></li><li><a href="/concepts/architecture.html">Arquitetura detalhada</a></li></ul>',11))])}const C=o(u,[["render",h]]);export{q as __pageData,C as default};
